const IDLE_MS = 10 * 60 * 1000; // 10 min braku aktywności → idle

// ─── Helpers ──────────────────────────────────────────────────────────────────
// In Tauri, relative paths like /uploads/... resolve to tauri://localhost — prepend server origin.
// STATIC_BASE comes from api.ts where BASE is already correctly resolved from VITE_API_BASE.
const staticUrl = (url: string | null | undefined): string =>
  !url ? '' : url.startsWith('/') ? `${STATIC_BASE}${url}` : url;

// Correct base for invite links — in Tauri window.location.origin is tauri://localhost
// so we use the real server origin from STATIC_BASE when available.
const APP_ORIGIN = STATIC_BASE || window.location.origin;

const ava = (u: { avatar_url?: string | null; username: string }) =>
  (u.avatar_url ? staticUrl(u.avatar_url) : null) || `https://api.dicebear.com/7.x/initials/svg?seed=${encodeURIComponent(u.username)}&size=40`;

const sc = (s: string) => {
  if (s === 'online') return 'bg-emerald-500';
  if (s === 'idle') return 'bg-amber-500';
  if (s === 'dnd') return 'bg-rose-500';
  return 'bg-zinc-500';
};

const ft = (iso: string) => new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
/** Module-level translate helper — reads saved locale so standalone components can use it. */
const tl = (key: string): string => {
  try { return translate(key, resolveLocale(loadLocale().locale)); } catch { return key; }
};

/** Module-level date formatter that respects the saved locale preference. */
const fmtDateLocale = (iso: string, opts?: Intl.DateTimeFormatOptions): string => {
  try {
    const { locale } = loadLocale();
    const tag = localeBcp47(resolveLocale(locale));
    return new Date(iso).toLocaleDateString(tag, opts ?? { day: 'numeric', month: 'long', year: 'numeric' });
  } catch { return new Date(iso).toLocaleDateString(); }
};
const fmtDur = (s: number) => `${String(Math.floor(s/60)).padStart(2,'0')}:${String(s%60).padStart(2,'0')}`;
const fmtGameDur = (startMs: number): string => {
  const sec = Math.floor((Date.now() - startMs) / 1000);
  if (sec < 60) return 'Przed chwilą';
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  return h > 0 ? `${h}h ${m}m` : `${m}m`;
};

