function EmojiPicker({ onSelect, onClose, serverEmojis }: { onSelect: (e: string) => void; onClose: () => void; serverEmojis?: ServerEmoji[] }) {
  const [cat, setCat] = React.useState(0);
  const ref = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) onClose(); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, [onClose]);
  const hasServerEmojis = serverEmojis && serverEmojis.length > 0;
  // cat === -1 means server emojis tab
  const effectiveCat = hasServerEmojis ? cat - 1 : cat;
  return (
    <div ref={ref}
      className="absolute bottom-full mb-2 right-0 w-80 bg-[#0e0e1c] border border-white/[0.12] rounded-3xl shadow-2xl shadow-black/80 overflow-hidden z-50" style={{backdropFilter:'blur(24px)'}}>
      {/* Category tabs */}
      <div className="flex overflow-x-auto border-b border-white/[0.07] p-1.5 gap-0.5"
        style={{ scrollbarWidth: 'none' }}>
        {hasServerEmojis && (
          <button onClick={() => setCat(0)} title="Emoji serwera"
            className={`text-base px-2 py-1.5 rounded-xl shrink-0 transition-colors ${cat === 0 ? 'bg-indigo-500/20 text-white' : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/[0.05]'}`}>
            ⭐
          </button>
        )}
        {EMOJI_CATS.map((c, i) => (
          <button key={i} onClick={() => setCat(hasServerEmojis ? i + 1 : i)} title={c.label}
            className={`text-base px-2 py-1.5 rounded-xl shrink-0 transition-colors ${cat === (hasServerEmojis ? i + 1 : i) ? 'bg-indigo-500/20 text-white' : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/[0.05]'}`}>
            {c.icon}
          </button>
        ))}
      </div>
      {/* Category label */}
      <div className="px-3 pt-2 pb-0.5">
        <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest">
          {hasServerEmojis && cat === 0 ? 'Emoji serwera' : EMOJI_CATS[effectiveCat]?.label}
        </p>
      </div>
      {/* Emoji grid */}
      <div className="p-2 gap-0.5 max-h-52 overflow-y-auto"
        style={{ scrollbarWidth: 'thin', scrollbarColor: '#3f3f46 transparent' }}>
        {hasServerEmojis && cat === 0 ? (
          <div className="grid grid-cols-8 gap-1">
            {serverEmojis!.map(e => (
              <button key={e.id} onClick={() => onSelect(`:${e.name}:`)} title={`:${e.name}:`}
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/[0.1] transition-colors hover:scale-110 active:scale-95">
                <img src={staticUrl(e.image_url)} alt={e.name} className="w-6 h-6 object-contain"/>
              </button>
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-9">
            {(EMOJI_CATS[effectiveCat]?.emojis as readonly string[] | undefined || []).map(emoji => (
              <button key={emoji} onClick={() => { onSelect(emoji); }}
                className="text-lg w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/[0.1] transition-colors hover:scale-110 active:scale-95">
                {emoji}
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Tenor GIF Picker ─────────────────────────────────────────────────────────
// Tenor API v1 — publiczny demo-klucz działa bez rejestracji
const TENOR_KEY = (import.meta.env.VITE_TENOR_API_KEY as string | undefined) || 'LIVDSRZULELA';

interface TenorGif { id: string; url: string; preview: string; }

function TenorGifPicker({ onSelect, onClose }: { onSelect: (url: string) => void; onClose: () => void }) {
  const [query, setQuery]     = useState('');
  const [pending, setPending] = useState('');
  const [results, setResults] = useState<TenorGif[]>([]);
  const [loading, setLoading] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const wrapRef  = useRef<HTMLDivElement>(null);

  useEffect(() => { inputRef.current?.focus(); }, []);

  // debounce 400 ms
  useEffect(() => {
    const t = setTimeout(() => setPending(query), 400);
    return () => clearTimeout(t);
  }, [query]);

  // fetch Tenor API v1
  useEffect(() => {
    setLoading(true);
    const ep = pending
      ? `https://api.tenor.com/v1/search?q=${encodeURIComponent(pending)}&key=${TENOR_KEY}&limit=24&media_filter=minimal&contentfilter=medium`
      : `https://api.tenor.com/v1/trending?key=${TENOR_KEY}&limit=24&media_filter=minimal&contentfilter=medium`;
    fetch(ep)
      .then(r => r.json())
      .then(data => setResults((data.results ?? []).map((r: any) => ({
        id:      r.id,
        url:     r.media?.[0]?.gif?.url     || '',
        preview: r.media?.[0]?.tinygif?.url || r.media?.[0]?.gif?.url || '',
      })).filter((g: TenorGif) => g.url)))
      .catch(() => setResults([]))
      .finally(() => setLoading(false));
  }, [pending]);

  // click-outside closes
  useEffect(() => {
    const h = (e: MouseEvent) => { if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) onClose(); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, [onClose]);

  return (
    <div ref={wrapRef}
      className="absolute bottom-full right-0 mb-2 w-80 bg-[#0d0d1a] border border-white/[0.12] rounded-2xl shadow-2xl shadow-black/80 z-[60] flex flex-col overflow-hidden"
      style={{maxHeight:'380px'}}>
      <div className="p-2 shrink-0 border-b border-white/[0.07]">
        <input ref={inputRef} value={query} onChange={e=>setQuery(e.target.value)}
          placeholder="Szukaj GIF-ów…"
          className="w-full bg-white/[0.06] border border-white/[0.08] rounded-xl px-3 py-1.5 text-sm text-zinc-200 placeholder-zinc-600 outline-none focus:border-indigo-500/40 transition-colors"/>
      </div>
      <div className="overflow-y-auto custom-scrollbar p-2 flex-1">
        {loading && results.length === 0 && (
          <div className="flex items-center justify-center py-8">
            <Loader2 size={18} className="animate-spin text-zinc-600"/>
          </div>
        )}
        {/* masonry — 2 kolumny, naturalne proporcje GIF-ów */}
        {results.length > 0 && (
          <div style={{columns:2, columnGap:'6px'}}>
            {results.map(gif => (
              <button key={gif.id} onClick={() => { onSelect(gif.url); onClose(); }}
                style={{breakInside:'avoid', display:'block', marginBottom:'6px', width:'100%'}}
                className="rounded-xl overflow-hidden hover:opacity-80 active:scale-95 transition-all focus:outline-none focus:ring-2 focus:ring-indigo-500/40">
                <img src={gif.preview} alt="" className="w-full h-auto rounded-xl block" loading="lazy"/>
              </button>
            ))}
          </div>
        )}
        {!loading && results.length === 0 && query && (
          <p className="text-xs text-zinc-600 text-center py-6">Brak wyników dla „{query}"</p>
        )}
      </div>
      <div className="shrink-0 px-3 py-1.5 border-t border-white/[0.05] flex justify-end">
        <span className="text-[9px] text-zinc-700 font-medium tracking-wide">Powered by Tenor</span>
      </div>
    </div>
  );
}

